CREATE OR REPLACE FUNCTION OFSERM.MINORITY_INTEREST_DATA_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_MINORITY_INTEREST(N_MIS_DATE_SKEY,N_ADDITIONAL_TIER1_AMOUNT,N_COMMON_EQUITY_TIER1_AMOUNT,N_MIN_REQUIRED_TIER1_PCT,N_MIN_REQ_AT1_PERCENT,N_MIN_REQ_CAPITAL_PERCENT,N_MIN_REQ_CET1_PERCENT,N_MIN_REQ_T2_PERCENT,N_THIRD_PARTY_INVST_AT1_PCT,N_THIRD_PARTY_INVST_CET1_PCT,N_THIRD_PARTY_INVST_T2_PCT,N_THIRD_PARTY_INVST_TIER1_PCT,N_THIRD_PARTY_INVST_TOTAL_PCT,N_TIER1_AMOUNT,N_TIER2_AMOUNT,N_TOTAL_CAPITAL_AMOUNT,N_TOTAL_RWA_AMOUNT,N_ENTITY_SKEY,N_GAAP_SKEY,N_RUN_SKEY)SELECT  /*+PARALLEL (4)*/ to_char(DIM_DATES.N_DATE_SKEY),COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0),COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0),COALESCE(MIN_CAPITAL.N_MIN_REQ_T1_PERCENT, 0) +COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0),(COALESCE(MIN_CAPITAL.N_MIN_REQ_T1_PERCENT, 0) +COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0) ) - (COALESCE(MIN_CAPITAL.N_MIN_REQ_CET1_PERCENT, 0) + COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0)),COALESCE(MIN_CAPITAL.N_MIN_REQ_TC_PERCENT, 0) +COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0),COALESCE(MIN_CAPITAL.N_MIN_REQ_CET1_PERCENT, 0) + COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0) + COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0) + COALESCE(MIN_CAPITAL.G_SIB,0),(COALESCE(MIN_CAPITAL.N_MIN_REQ_TC_PERCENT, 0)+COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0)) - (COALESCE(MIN_CAPITAL.N_MIN_REQ_T1_PERCENT, 0)+COALESCE(MIN_CAPITAL.N_MIN_REQ_CCB, 0)+ COALESCE(MIN_CAPITAL.N_MIN_REQ_COUNTER_CYCL_BUFFER, 0)+ COALESCE(MIN_CAPITAL.G_SIB,0)),COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_AT1_PCT, 0),COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_CET1_PCT, 0),COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_T2_PCT, 0),( (COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_CET1_PCT, 0) * COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0))+ (COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_AT1_PCT, 0)*COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0)) )/(COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0)+COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0)),( (COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_CET1_PCT, 0) * COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0))+ (COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_AT1_PCT, 0)*COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0)) +(COALESCE(FCT_ENTITY_INFO.N_THIRD_PARTY_INVST_T2_PCT, 0)*COALESCE(FCT_ENTITY_INFO.N_TIER2_AMOUNT, 0)))/(COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0)+COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0)++COALESCE(FCT_ENTITY_INFO.N_TIER2_AMOUNT, 0)),COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0) + COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0),COALESCE(FCT_ENTITY_INFO.N_TIER2_AMOUNT, 0),COALESCE(FCT_ENTITY_INFO.N_ADDITIONAL_TIER1_AMOUNT, 0) + COALESCE(FCT_ENTITY_INFO.N_COMMON_EQUITY_TIER1_AMOUNT, 0) + COALESCE(FCT_ENTITY_INFO.N_TIER2_AMOUNT, 0),COALESCE(FCT_CAPITAL_ACCT_HEAD.N_CAPITAL_ACCT_HEAD_AMT, 0),to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FCT_ENTITY_INFO.N_GAAP_SKEY),to_char(FCT_ENTITY_INFO.N_RUN_SKEY) FROM FCT_ENTITY_INFO JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FCT_ENTITY_INFO.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FCT_ENTITY_INFO.N_MIS_DATE_SKEY AND DIM_DATES.d_calendar_date = to_date('20260331','YYYYMMDD') LEFT JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FCT_ENTITY_INFO.N_GAAP_SKEY INNER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = 'CAP838' and to_date('20260331','YYYYMMDD') between DIM_STANDARD_ACCT_HEAD.d_Record_start_date and DIM_STANDARD_ACCT_HEAD.d_record_end_date LEFT JOIN FCT_CAPITAL_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FCT_CAPITAL_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY AND FCT_CAPITAL_ACCT_HEAD.N_ENTITY_SKEY = FCT_ENTITY_INFO.N_ENTITY_SKEY AND FCT_CAPITAL_ACCT_HEAD.N_MIS_DATE_SKEY = FCT_ENTITY_INFO.N_MIS_DATE_SKEY AND FCT_CAPITAL_ACCT_HEAD.N_RUN_SKEY = FCT_ENTITY_INFO.N_RUN_SKEY AND FCT_CAPITAL_ACCT_HEAD.N_GAAP_SKEY = FCT_ENTITY_INFO.N_GAAP_SKEY LEFT JOIN ( SELECT TRANSPOSE.V_CAP_ADEQUACY_REGULATOR_CODE, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP820', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) N_MIN_REQ_CET1_PERCENT, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP821', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) N_MIN_REQ_T1_PERCENT, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP822', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) N_MIN_REQ_TC_PERCENT, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP823', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) N_MIN_REQ_CCB, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP819', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) N_MIN_REQ_COUNTER_CYCL_BUFFER, MAX(DECODE(TRANSPOSE.V_STD_ACCT_HEAD_ID, 'CAP824', TRANSPOSE.N_CAPITAL_COMPONENT_VALUE)) G_SIB FROM ( SELECT FSI_SETUP_CAPITAL_HEAD.V_CAPITAL_ADEQUACY_REGULATOR V_CAP_ADEQUACY_REGULATOR_CODE, FSI_SETUP_CAPITAL_HEAD.V_STD_ACCT_HEAD_ID V_STD_ACCT_HEAD_ID, FSI_SETUP_CAPITAL_HEAD.V_STD_ACCT_HEAD_DESC V_CAPITAL_COMPONENT_DESC, FSI_SETUP_CAPITAL_HEAD.N_CAPITAL_COMPONENT_VALUE N_CAPITAL_COMPONENT_VALUE, FSI_SETUP_CAPITAL_HEAD.D_START_DATE D_START_DATE, FSI_SETUP_CAPITAL_HEAD.D_END_DATE D_END_DATE FROM FSI_SETUP_CAPITAL_HEAD LEFT JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = FSI_SETUP_CAPITAL_HEAD.V_STD_ACCT_HEAD_ID WHERE DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IN ( 'CAP820', 'CAP821', 'CAP822', 'CAP823', 'CAP819', 'CAP824' ) AND ( to_date('20260331','YYYYMMDD') BETWEEN FSI_SETUP_CAPITAL_HEAD.D_START_DATE AND FSI_SETUP_CAPITAL_HEAD.D_END_DATE ) AND ( to_date('20260331','YYYYMMDD') BETWEEN DIM_STANDARD_ACCT_HEAD.D_RECORD_START_DATE AND DIM_STANDARD_ACCT_HEAD.D_RECORD_END_DATE ) ) TRANSPOSE GROUP BY TRANSPOSE.V_CAP_ADEQUACY_REGULATOR_CODE ) MIN_CAPITAL ON MIN_CAPITAL.V_CAP_ADEQUACY_REGULATOR_CODE = FCT_ENTITY_INFO.V_CAPITAL_ADEQUACY_REGULATOR WHERE 1=1 AND FCT_ENTITY_INFO.F_THIRDPARTY_MINORITY_HOLD_IND = 'Y' LOG ERRORS INTO FSI_MINORITY_INTEREST$ ('1776770955958_24414854_20260331_1_Job_4747dfa8f04c490e9fe26ad460520b93') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
